import{_ as t,o,c as r,a2 as i}from"./chunks/framework.OWFDNrRT.js";const m=JSON.parse('{"title":"Modding Systems Research: 15 Industry-Leading Games","description":"","frontmatter":{},"headers":[],"relativePath":"modding-research.md","filePath":"modding-research.md","lastUpdated":1773459185000}'),a={name:"modding-research.md"};function n(s,e,l,d,g,c){return o(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="modding-systems-research-15-industry-leading-games" tabindex="-1">Modding Systems Research: 15 Industry-Leading Games <a class="header-anchor" href="#modding-systems-research-15-industry-leading-games" aria-label="Permalink to &quot;Modding Systems Research: 15 Industry-Leading Games&quot;">​</a></h1><p><strong>Purpose</strong>: Analyze proven modding architectures to inform DINOForge&#39;s design as a BepInEx-based mod platform for Diplomacy is Not an Option (DINO).</p><p><strong>Date</strong>: March 2026 <strong>Scope</strong>: Mod format, load systems, content scope, dependency management, distribution, no-code paths, strengths, weaknesses, and relevance to DINOForge.</p><hr><h2 id="quick-comparison-table" tabindex="-1">Quick Comparison Table <a class="header-anchor" href="#quick-comparison-table" aria-label="Permalink to &quot;Quick Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Game</th><th>Format</th><th>No-Code Path</th><th>Content Scope</th><th>Distribution</th><th>Key Strength</th></tr></thead><tbody><tr><td><strong>Factorio</strong></td><td>Lua (structured)</td><td>Partial (data.lua)</td><td>Prototypes, scripts, assets</td><td>Factorio Mods portal</td><td>Data lifecycle standardization</td></tr><tr><td><strong>Stardew Valley</strong></td><td>JSON (Content Patcher)</td><td>Full</td><td>Graphics, data, maps, dialogue</td><td>Nexus, CurseForge, SMAPI</td><td>JSON-only content without C#</td></tr><tr><td><strong>RimWorld</strong></td><td>XML + C# (Harmony)</td><td>Full (XML only)</td><td>Defs, behaviors, mechanics</td><td>Steam Workshop</td><td>XML blueprint + optional patches</td></tr><tr><td><strong>Crusader Kings III</strong></td><td>PDX script</td><td>Partial</td><td>Game rules, map, cultures</td><td>Steam Workshop, Paradox Mods</td><td>Total conversions (CK2→CK3 converters)</td></tr><tr><td><strong>Stellaris</strong></td><td>PDX script</td><td>Partial</td><td>Empires, events, buildings</td><td>Steam Workshop, Paradox Mods</td><td>Community-driven total conversions</td></tr><tr><td><strong>Total War: Warhammer III</strong></td><td>Binary (.pack) + RPFM</td><td>No</td><td>Tables, scripts, data</td><td>Steam Workshop</td><td>RPFM tool ecosystem</td></tr><tr><td><strong>Kerbal Space Program</strong></td><td>C# + .cfg</td><td>Partial (.cfg only)</td><td>Parts, behaviors, plugins</td><td>CKAN (package manager)</td><td>CKAN dependency resolution</td></tr><tr><td><strong>Mount &amp; Blade II: Bannerlord</strong></td><td>C# + XML</td><td>Partial (XML only)</td><td>Scenes, items, characters</td><td>Nexus, Steam Workshop</td><td>Official tools + SubModule.xml structure</td></tr><tr><td><strong>The Sims 4</strong></td><td>Python + .package</td><td>No</td><td>Game objects, behaviors, tuning</td><td>CurseForge, TSR</td><td>Package format + Python scripting</td></tr><tr><td><strong>Cities: Skylines</strong></td><td>C# (compiled DLL)</td><td>No</td><td>Buildings, behaviors, UI</td><td>Steam Workshop</td><td>Unified C# API</td></tr><tr><td><strong>Minecraft</strong></td><td>JSON (datapacks)</td><td>Full</td><td>Recipes, loot, structures, functions</td><td>Modrinth, CurseForge</td><td>JSON datapacks + Fabric/Forge loaders</td></tr><tr><td><strong>Skyrim / Fallout 4</strong></td><td>Binary (ESP/ESM)</td><td>No</td><td>Content via Creation Kit</td><td>Nexus Mods</td><td>Creation Kit GUI tool</td></tr><tr><td><strong>OpenTTD</strong></td><td>NewGRF (NML)</td><td>No (binary format)</td><td>Vehicles, buildings, cargo</td><td>Community forums, steam</td><td>Open source + NML high-level language</td></tr><tr><td><strong>Victoria 3</strong></td><td>PDX script</td><td>Partial</td><td>Rules, events, decisions</td><td>Paradox Mods</td><td>Jomini engine evolution</td></tr><tr><td><strong>Dwarf Fortress</strong></td><td>RAW (text)</td><td>Full</td><td>Creatures, items, materials</td><td>Steam Workshop, DFFD</td><td>Declarative text modification</td></tr></tbody></table><hr><h2 id="detailed-analysis-by-game" tabindex="-1">Detailed Analysis by Game <a class="header-anchor" href="#detailed-analysis-by-game" aria-label="Permalink to &quot;Detailed Analysis by Game&quot;">​</a></h2><h3 id="_1-factorio-data-lifecycle-mastery" tabindex="-1">1. Factorio - Data Lifecycle Mastery <a class="header-anchor" href="#_1-factorio-data-lifecycle-mastery" aria-label="Permalink to &quot;1. Factorio - Data Lifecycle Mastery&quot;">​</a></h3><p><strong>Mod Format</strong>: Lua scripts organized by lifecycle stage <strong>File Structure</strong>: <code>info.json</code>, <code>data.lua</code>, <code>data-updates.lua</code>, <code>data-final-fixes.lua</code>, <code>control.lua</code>, <code>settings.lua</code></p><p><strong>Load System</strong>:</p><ul><li>Mods loaded as zip or folder (<code>{name}_{version}</code> or <code>{name}</code>)</li><li>Single shared Lua state per stage</li><li>Three-phase data construction: data → updates → final-fixes</li><li>Runtime Lua state per mod for event handling</li></ul><p><strong>Content Types</strong>:</p><ul><li>Prototypes (items, entities, technologies, recipes, buildings)</li><li>Scripting (events, commands, remote interfaces)</li><li>Settings (player-configurable mod options)</li><li>Graphics and localizations</li></ul><p><strong>Dependency Management</strong>:</p><ul><li>Mods can declare dependencies in <code>info.json</code></li><li>Mod portal handles version compatibility</li><li>Load order determined by dependency graph</li></ul><p><strong>Distribution</strong>: <a href="https://mods.factorio.com/" target="_blank" rel="noreferrer">Factorio Mods Portal</a> (built-in in-game mod manager)</p><p><strong>No-Code Path</strong>: Partial—mods can be pure data (prototypes) without scripting, but dynamic behavior requires <code>control.lua</code></p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Data Lifecycle Standardization</strong>: Three-phase load ensures consistent override ordering (data → updates → final-fixes)</li><li><strong>Modular Lua States</strong>: Each mod gets isolated runtime state, reducing conflicts</li><li><strong>Built-in Mod Manager</strong>: Integrated discovery, installation, versioning</li><li><strong>Simple Text Format</strong>: <code>info.json</code> is human-readable and git-friendly</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Lua required for anything beyond prototypes</li><li>No visual GUI for config (JSON-style settings only)</li><li>Factorio modding has steep learning curve for complex mechanics</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: Lifecycle concept (data → apply → final-fixes) maps well to pack loading phases</li><li><strong>Adapt</strong>: Three-phase could be <code>base-pack.yaml → balance-override.yaml → conflict-resolution.yaml</code></li><li><strong>Avoid</strong>: Don&#39;t force Lua; JSON/YAML is sufficient for most RTS mod types (units, buildings, factions)</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://wiki.factorio.com/Modding" target="_blank" rel="noreferrer">Factorio Modding Wiki</a></li><li><a href="https://lua-api.factorio.com/latest/" target="_blank" rel="noreferrer">Factorio Lua API</a></li><li><a href="https://lua-api.factorio.com/latest/auxiliary/mod-structure.html" target="_blank" rel="noreferrer">Mod Structure Documentation</a></li></ul><hr><h3 id="_2-stardew-valley-smapi-content-patcher-json-only-content" tabindex="-1">2. Stardew Valley + SMAPI + Content Patcher - JSON-Only Content <a class="header-anchor" href="#_2-stardew-valley-smapi-content-patcher-json-only-content" aria-label="Permalink to &quot;2. Stardew Valley + SMAPI + Content Patcher - JSON-Only Content&quot;">​</a></h3><p><strong>Mod Format</strong>: JSON-based content patches (Content Patcher) <strong>File Structure</strong>: <code>manifest.json</code>, <code>content.json</code>, asset folders</p><p><strong>Load System</strong>:</p><ul><li>SMAPI is the mod loader (Stardew Modding API)</li><li>Content Patcher is a SMAPI mod (not code mods)</li><li>JSON patches applied in order: Load, EditData, EditImage, EditMap</li><li>Validation via <a href="https://smapi.io/json" target="_blank" rel="noreferrer">smapi.io/json</a></li></ul><p><strong>Content Types</strong>:</p><ul><li>Game assets (images, data, dialogue)</li><li>Map modifications</li><li>Data entry edits (conditional by date, weather, location, spouse, etc.)</li><li>No code required</li></ul><p><strong>Dependency Management</strong>:</p><ul><li>Manifest lists dependencies + versions</li><li>SMAPI enforces dependency order</li><li>Conflict detection and reporting</li></ul><p><strong>Distribution</strong>: <a href="https://www.nexusmods.com/stardewvalley" target="_blank" rel="noreferrer">Nexus Mods</a>, <a href="https://www.curseforge.com/stardewvalley" target="_blank" rel="noreferrer">CurseForge</a></p><p><strong>No-Code Path</strong>: <strong>Full</strong> — all modding possible without writing C#</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Pure JSON Content Patcher</strong>: Zero code required; patches are declarative</li><li><strong>Conditional Logic</strong>: Patches apply conditionally (date, location, NPC spouse, etc.)</li><li><strong>Automatic Compatibility Checks</strong>: SMAPI validates manifests before load</li><li><strong>Asset Replacement</strong>: Simple Load/Edit paradigm—no file format knowledge needed</li><li><strong>Auto-Update Support</strong>: Built-in update checking and compatibility reports</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Limited to asset/data replacement; can&#39;t add new game mechanics</li><li>SMAPI required (not part of base game)</li><li>Conditional syntax is JSON-heavy (not intuitive for non-coders)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: Content Patcher&#39;s conditional patch system (date/location) is perfect for scenario modding</li><li><strong>Adapt</strong>: DINOForge should support no-code YAML pack format for balance/unit mods</li><li><strong>Target Design</strong>: <code>units.yaml</code> + <code>conditions.yaml</code> for faction/unit overrides without C#</li><li><strong>Conflict Detection</strong>: Implement similar manifest validation as SMAPI</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://stardewvalleywiki.com/Modding:Content_Patcher" target="_blank" rel="noreferrer">Content Patcher Documentation</a></li><li><a href="https://smapi.io/mods" target="_blank" rel="noreferrer">SMAPI Mod Compatibility</a></li><li><a href="https://www.nexusmods.com/stardewvalley/mods/1915" target="_blank" rel="noreferrer">Nexus Content Patcher Page</a></li></ul><hr><h3 id="_3-rimworld-xml-defs-harmony-patching" tabindex="-1">3. RimWorld - XML Defs + Harmony Patching <a class="header-anchor" href="#_3-rimworld-xml-defs-harmony-patching" aria-label="Permalink to &quot;3. RimWorld - XML Defs + Harmony Patching&quot;">​</a></h3><p><strong>Mod Format</strong>: XML definitions + optional C# Harmony patches <strong>File Structure</strong>: <code>About/About.xml</code>, <code>Defs/</code> (XML files), <code>Assemblies/</code> (DLLs with Harmony patches)</p><p><strong>Load System</strong>:</p><ul><li>Load order specified in <code>About.xml</code></li><li>XML defs inherit from C# Def classes</li><li>Harmony patches applied to methods (pre/post hooks, replacements)</li><li>Mod folders or <code>.rar</code> files</li></ul><p><strong>Content Types</strong>:</p><ul><li>Defs (items, buildings, factions, technologies, animals)</li><li>Behaviors via Harmony method patches</li><li>Custom C# code in DLLs</li></ul><p><strong>Dependency Management</strong>:</p><ul><li><code>About.xml</code> lists dependencies and load order</li><li>No version tracking (manual)</li><li>Community tracks conflicts</li></ul><p><strong>Distribution</strong>: Steam Workshop, Nexus Mods</p><p><strong>No-Code Path</strong>: <strong>Full</strong> — pure XML mods define new content (buildings, items, factions)</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Separation of Data and Code</strong>: XML for defs, C# for complex behavior</li><li><strong>Harmony Ecosystem</strong>: De facto standard for method patching (used by many games)</li><li><strong>Simple Inheritance</strong>: XML defs inherit from base classes automatically</li><li><strong>Hot Reload Friendly</strong>: Can add new Defs without recompiling</li><li><strong>Massive Community</strong>: 10K+ mods, well-documented tooling</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>XML inheritance rules are implicit (not always obvious)</li><li>Load order errors cause silent failures or crashes</li><li>Harmony patches are fragile (game updates break them)</li><li>No dependency versioning (semver not enforced)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: XML Def pattern is perfect for units, buildings, factions</li><li><strong>Adapt</strong>: YAML equivalent: <code>units.yaml</code> inherits from base unit archetype</li><li><strong>Improve</strong>: Add explicit schema validation (JSON Schema) instead of silent failures</li><li><strong>Avoid</strong>: Don&#39;t mimic Harmony&#39;s method-patching fragility; use registry-based overrides</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://rimworldmodding.wiki.gg/wiki/Basic_Concepts" target="_blank" rel="noreferrer">RimWorld Modding Wiki</a></li><li><a href="https://rimworldwiki.com/wiki/Modding_Tutorials/XML_Defs" target="_blank" rel="noreferrer">XML Defs Tutorial</a></li><li><a href="https://github.com/pardeike/HarmonyRimWorld" target="_blank" rel="noreferrer">Harmony RimWorld</a></li></ul><hr><h3 id="_4-crusader-kings-iii-paradox-pdx-scripting" tabindex="-1">4. Crusader Kings III - Paradox PDX Scripting <a class="header-anchor" href="#_4-crusader-kings-iii-paradox-pdx-scripting" aria-label="Permalink to &quot;4. Crusader Kings III - Paradox PDX Scripting&quot;">​</a></h3><p><strong>Mod Format</strong>: PDX script (text-based declarative language) <strong>File Structure</strong>: <code>/common/</code> (events, decisions, characters), <code>/map/</code> (provinces, borders)</p><p><strong>Load System</strong>:</p><ul><li>Mod folders with <code>.mod</code> descriptor file</li><li>Steam Workshop integration</li><li>PDX script parser loads and merges files</li><li>Load order by folder name and dependency tracking</li></ul><p><strong>Content Types</strong>:</p><ul><li>Rules and mechanics (events, decisions, claims, titles)</li><li>Map and provinces</li><li>Character traits and culture</li><li>Government types and succession laws</li></ul><p><strong>Dependency Management</strong>:</p><ul><li><code>.mod</code> files list dependencies</li><li>Mod portal enforces compatibility</li><li>Version checking built-in</li></ul><p><strong>Distribution</strong>: <a href="https://steamcommunity.com/workshop/browse/?appid=1158310" target="_blank" rel="noreferrer">Steam Workshop</a>, <a href="https://mods.paradoxplaza.com/games/ck3" target="_blank" rel="noreferrer">Paradox Mods</a></p><p><strong>No-Code Path</strong>: Partial—new rules require PDX script; can&#39;t add purely data-driven rules without code</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Total Conversions</strong>: Mods like Shogunate, Princes of Darkness redefine entire game</li><li><strong>Game Converters</strong>: Community tools convert CK2→CK3, EU4→CK3</li><li><strong>Live Editing</strong>: PDX syntax is relatively intuitive</li><li><strong>Built-in Workshop</strong>: Seamless Steam distribution</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>PDX script is proprietary; documentation is sparse</li><li>Syntax errors cause silent failures or crashes</li><li>Requires understanding game&#39;s internal rule system</li><li>Total conversions are 5K+ file projects (high barrier to entry)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Avoid</strong>: PDX script is too proprietary for an open-source project</li><li><strong>Adapt</strong>: Document YAML rule syntax clearly (DINOForge&#39;s equivalent of PDX script)</li><li><strong>Learn</strong>: Total conversions show value of well-designed base game abstraction</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://ck3.paradoxwikis.com/Modding" target="_blank" rel="noreferrer">CK3 Modding Wiki</a></li><li><a href="https://gamerant.com/crusader-kings-3-ck3-best-total-conversion-mods/" target="_blank" rel="noreferrer">Best CK3 Total Conversions</a></li><li><a href="https://mods.paradoxplaza.com/games/ck3" target="_blank" rel="noreferrer">Paradox Mods</a></li></ul><hr><h3 id="_5-stellaris-total-conversions-community-scale" tabindex="-1">5. Stellaris - Total Conversions &amp; Community Scale <a class="header-anchor" href="#_5-stellaris-total-conversions-community-scale" aria-label="Permalink to &quot;5. Stellaris - Total Conversions &amp; Community Scale&quot;">​</a></h3><p><strong>Mod Format</strong>: PDX script (same as CK3) <strong>Content Types</strong>: Star Wars, Warhammer 40K total conversions popular</p><p><strong>Load System</strong>: Same as CK3 (Steam Workshop, dependency tracking)</p><p><strong>Distribution</strong>: <a href="https://steamcommunity.com/workshop/browse/?appid=281990&amp;requiredtags%5B%5D=Total+Conversion" target="_blank" rel="noreferrer">Steam Workshop</a>, <a href="https://mods.paradoxplaza.com/games/stellaris" target="_blank" rel="noreferrer">Paradox Mods</a></p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Community Total Conversions</strong>: Warhammer 40K has 1200+ systems, 32 empires, 25 planet types</li><li><strong>Active Modding Community</strong>: Mods with detailed balance tuning, lore integration</li><li><strong>Scale</strong>: Mods rival official DLC in scope (one person or small team creates 5K+ system empires)</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Same as CK3: proprietary script, documentation gaps</li><li>Performance issues with large total conversions (1200+ systems)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Target</strong>: DINOForge should enable Star Wars / WH40K scale mods for DINO</li><li><strong>Learn</strong>: Community&#39;s ability to create total conversions shows value of declarative modding</li><li><strong>Plan</strong>: DINO is smaller than Stellaris (single map), but same principle applies</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://forum.paradoxplaza.com/forum/threads/mod-warhammer-40k-total-conversion.988421/" target="_blank" rel="noreferrer">Warhammer 40K Total Conversion</a></li><li><a href="https://github.com/kamip123/Stellaris-Warhammer-30k-Scenario" target="_blank" rel="noreferrer">GitHub: Stellaris Warhammer Mod</a></li><li><a href="https://steamcommunity.com/workshop/browse/?appid=281990" target="_blank" rel="noreferrer">Stellaris Workshop</a></li></ul><hr><h3 id="_6-total-war-warhammer-iii-rpfm-pack-files" tabindex="-1">6. Total War: Warhammer III - RPFM &amp; Pack Files <a class="header-anchor" href="#_6-total-war-warhammer-iii-rpfm-pack-files" aria-label="Permalink to &quot;6. Total War: Warhammer III - RPFM &amp; Pack Files&quot;">​</a></h3><p><strong>Mod Format</strong>: Binary <code>.pack</code> files (edited via RPFM tool) <strong>File Structure</strong>: <code>.pack</code> containers with DB tables, scripts, text (loc files)</p><p><strong>Load System</strong>:</p><ul><li>RPFM (Rusted PackFile Manager) edits <code>.pack</code> files</li><li>Mod folders loaded by launcher</li><li>Pack files override vanilla data</li></ul><p><strong>Content Types</strong>:</p><ul><li>Database tables (units, buildings, factions, stats)</li><li>Scripts and event handlers</li><li>Localizations (text strings)</li></ul><p><strong>Dependency Management</strong>: Not formally versioned; manual override system</p><p><strong>Distribution</strong>: Steam Workshop</p><p><strong>No-Code Path</strong>: No—all modding requires RPFM binary editor</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Total War Tradition</strong>: Large total conversion community (Warhammer Fantasy, Napoleonic Era)</li><li><strong>RPFM Ecosystem</strong>: Open-source tool handles <code>.pack</code> format decoding/encoding</li><li><strong>Massive Tables</strong>: Can override unit stats, building effects, faction mechanics</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li><strong>Binary Format</strong>: Mods are <code>.pack</code> files, not human-readable</li><li><strong>Tool Dependency</strong>: RPFM is required; no other editors</li><li><strong>Fragile Compatibility</strong>: Binary format changes break mods across game updates</li><li><strong>High Barrier</strong>: Beginners need RPFM tutorial (steep learning curve)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Avoid</strong>: Binary <code>.pack</code> format is not suitable for open-source, collaborative modding</li><li><strong>Learn Negatively</strong>: RPFM tooling is necessary but shows pain of binary-only modding</li><li><strong>Contrast</strong>: DINOForge&#39;s YAML-based packs are human-readable and git-friendly</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://github.com/Frodo45127/rpfm" target="_blank" rel="noreferrer">RPFM GitHub</a></li><li><a href="https://tw-modding.com/wiki/Tutorial:RPFM_For_Dummies" target="_blank" rel="noreferrer">RPFM for Dummies</a></li><li><a href="https://gameplay.tips/guides/total-war-warhammer-iii-modding-start.html" target="_blank" rel="noreferrer">Total War Warhammer III Modding</a></li></ul><hr><h3 id="_7-kerbal-space-program-ckan-package-management" tabindex="-1">7. Kerbal Space Program - CKAN Package Management <a class="header-anchor" href="#_7-kerbal-space-program-ckan-package-management" aria-label="Permalink to &quot;7. Kerbal Space Program - CKAN Package Management&quot;">​</a></h3><p><strong>Mod Format</strong>: C# plugins (DLLs) + Module Manager <code>.cfg</code> config files <strong>File Structure</strong>: <code>GameData/</code> folder hierarchy, <code>.ckan</code> metadata files</p><p><strong>Load System</strong>:</p><ul><li>CKAN is a package manager (NixOS/Debian-inspired)</li><li>Mods install with dependencies, version checking</li><li>Module Manager patched game configs without overriding files</li><li>Hot-reload capable</li></ul><p><strong>Content Types</strong>:</p><ul><li>Parts (custom spacecraft components)</li><li>Plugins (mechanics, UI, integrations)</li><li>Configurations (balance tweaks via Module Manager)</li></ul><p><strong>Dependency Management</strong>: <strong>CKAN is exceptional</strong> — semantic versioning, conflict resolution, dependency lockfiles</p><p><strong>Distribution</strong>: CKAN registry, CurseForge, Nexus Mods</p><p><strong>No-Code Path</strong>: Partial—Module Manager allows <code>.cfg</code> tweaks without code</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>CKAN Package Manager</strong>: Best-in-class dependency resolution (inspired by Debian/CPAN)</li><li><strong>Semantic Versioning</strong>: Mods can specify <code>&gt;=1.0.0, &lt;2.0.0</code> constraints</li><li><strong>Module Manager</strong>: Non-programmer can patch game configs</li><li><strong>Multi-Platform</strong>: CKAN runs on Windows, macOS, Linux (Mono-based)</li><li><strong>Metadata Standard</strong>: JSON schema ensures consistency</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Two-tier system (CKAN + Module Manager) is confusing for new modders</li><li>KSP&#39;s modding is historically fragile (breaks on game updates)</li><li>Requires understanding C# for part definitions</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: CKAN&#39;s dependency resolution model is gold standard</li><li><strong>Plan</strong>: DINOForge should implement similar package manager (or wrap NuGet)</li><li><strong>Target</strong>: Semantic versioning for pack compatibility (<code>&gt;=0.2.0, &lt;1.0.0</code>)</li><li><strong>Avoid</strong>: Don&#39;t create two-tier system; keep YAML packs simple</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://github.com/KSP-CKAN/CKAN" target="_blank" rel="noreferrer">CKAN GitHub</a></li><li><a href="https://github.com/KSP-CKAN/CKAN/wiki" target="_blank" rel="noreferrer">CKAN Wiki</a></li><li><a href="https://forum.kerbalspaceprogram.com/topic/90246-the-comprehensive-kerbal-archive-network-ckan-package-manager-v1180-19-june-2016/" target="_blank" rel="noreferrer">CKAN Package Manager (Forum)</a></li></ul><hr><h3 id="_8-mount-blade-ii-bannerlord-official-tools-xml" tabindex="-1">8. Mount &amp; Blade II: Bannerlord - Official Tools + XML <a class="header-anchor" href="#_8-mount-blade-ii-bannerlord-official-tools-xml" aria-label="Permalink to &quot;8. Mount &amp; Blade II: Bannerlord - Official Tools + XML&quot;">​</a></h3><p><strong>Mod Format</strong>: C# modules with <code>SubModule.xml</code> manifests <strong>File Structure</strong>: <code>/Modules/{ModName}/SubModule.xml</code>, <code>/ModuleData/</code>, <code>/Bin/</code></p><p><strong>Load System</strong>:</p><ul><li>Launcher reads <code>SubModule.xml</code> for each mod folder</li><li>Mods inherit from <code>MBSubModuleBase</code> (entry point)</li><li>DLL files loaded in order, <code>OnSubModuleLoad()</code> called at startup</li><li>XML patches applied to game data</li></ul><p><strong>Content Types</strong>:</p><ul><li>Scenes and maps</li><li>Items and equipment</li><li>Characters and troops</li><li>Custom mechanics (via C# patches)</li></ul><p><strong>Dependency Management</strong>: Mod load order in launcher UI, no automatic versioning</p><p><strong>Distribution</strong>: Nexus Mods, Steam Workshop</p><p><strong>No-Code Path</strong>: Partial—XML mods can define items, troops, scenes; complex behavior requires C#</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Official Tools</strong>: Bannerlord provides visual scene editor and asset tools</li><li><strong>SubModule.xml Standard</strong>: Clear manifest format, well-documented</li><li><strong>XML + Code</strong>: Separation of concerns (declarative data + imperative logic)</li><li><strong>Community Resources</strong>: Good tutorials, module templates on Nexus</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Load order management is manual (no dependency resolution)</li><li>C# required for anything beyond XML definitions</li><li>No versioning enforcement</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: SubModule.xml pattern is excellent—DINOForge&#39;s <code>pack.yaml</code> is equivalent</li><li><strong>Adopt</strong>: Separation of data (YAML) and behavior (C#) is core DINOForge principle</li><li><strong>Improve</strong>: Add semantic versioning to pack.yaml (Bannerlord doesn&#39;t have this)</li><li><strong>Learn</strong>: Official tools (scene editor) show value of GUI support</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://docs.bannerlordmodding.com/" target="_blank" rel="noreferrer">Bannerlord Modding Documentation</a></li><li><a href="https://docs.bannerlordmodding.com/_xmldocs/submodule.html" target="_blank" rel="noreferrer">SubModule.xml Documentation</a></li><li><a href="https://docs.bannerlordmodding.com/_tutorials/basic-csharp-mod.html" target="_blank" rel="noreferrer">Basic C# Mod Tutorial</a></li></ul><hr><h3 id="_9-the-sims-4-python-package-format" tabindex="-1">9. The Sims 4 - Python + Package Format <a class="header-anchor" href="#_9-the-sims-4-python-package-format" aria-label="Permalink to &quot;9. The Sims 4 - Python + Package Format&quot;">​</a></h3><p><strong>Mod Format</strong>: Python scripts + <code>.package</code> binary files <strong>File Structure</strong>: Mod mods/ folder, .ts4script files</p><p><strong>Load System</strong>:</p><ul><li>Game scans mods/ folder for <code>.ts4script</code> files</li><li>Python scripts have direct game API access</li><li><code>.package</code> files contain tuning (game object definitions)</li><li>Sims4Studio tool edits <code>.package</code> files</li></ul><p><strong>Content Types</strong>:</p><ul><li>Game objects (furniture, characters, interactions)</li><li>Custom behaviors (Python scripts)</li><li>Tuning files (XML-like data)</li><li>Cheats and automation tools</li></ul><p><strong>Dependency Management</strong>: None (mods are independent)</p><p><strong>Distribution</strong>: CurseForge, The Sims Resource, Nexus Mods</p><p><strong>No-Code Path</strong>: No—even simple object additions require Python</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Python Scripting</strong>: More accessible than C# for new modders</li><li><strong>Large Community</strong>: 10K+ active mod creators</li><li><strong>Sims4Studio Tool</strong>: Visual editor for <code>.package</code> files (reduces friction)</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Binary <code>.package</code> format is not human-readable or git-friendly</li><li>Python API is poorly documented (reverse-engineered)</li><li>No dependency management (mods can break each other silently)</li><li>Decompiling required to understand game code (legal gray area)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Avoid</strong>: Binary format is a pain point; DINOForge&#39;s YAML is better</li><li><strong>Avoid</strong>: Python for game modding adds complexity; C# is more integrated</li><li><strong>Learn</strong>: Large community shows value of accessible tooling (Sims4Studio)</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://lot51.cc/simdex/resources" target="_blank" rel="noreferrer">Lot 51 Modding Guide</a></li><li><a href="https://sims-4-modding.fandom.com/wiki/Python_Scripting" target="_blank" rel="noreferrer">Sims 4 Modding Wiki</a></li><li><a href="https://www.curseforge.com/sims4" target="_blank" rel="noreferrer">CurseForge Sims 4 Mods</a></li></ul><hr><h3 id="_10-cities-skylines-c-workshop-mods" tabindex="-1">10. Cities: Skylines - C# Workshop Mods <a class="header-anchor" href="#_10-cities-skylines-c-workshop-mods" aria-label="Permalink to &quot;10. Cities: Skylines - C# Workshop Mods&quot;">​</a></h3><p><strong>Mod Format</strong>: C# source code (compiled to DLL, uploaded to Workshop) <strong>File Structure</strong>: C# project, compiled to <code>.dll</code>, uploaded via Steam Workshop</p><p><strong>Load System</strong>:</p><ul><li>Workshop mods auto-downloaded</li><li>DLLs loaded into game runtime (Unity)</li><li>ModTools provides debugging/inspection</li></ul><p><strong>Content Types</strong>:</p><ul><li>Buildings and assets (new city structures)</li><li>Mechanics (traffic, economy, simulation)</li><li>UI overlays</li></ul><p><strong>Dependency Management</strong>: Manual (no versioning)</p><p><strong>Distribution</strong>: Steam Workshop only</p><p><strong>No-Code Path</strong>: No—all mods are C#</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Direct Unity Access</strong>: Mods have full access to game engine</li><li><strong>Workshop Integration</strong>: Seamless Steam distribution</li><li><strong>ModTools</strong>: In-game debugging tool for mod development</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li><strong>No No-Code Path</strong>: All mods require C# knowledge</li><li><strong>No Dependency Management</strong>: Mods can break each other</li><li><strong>Compilation Barrier</strong>: C# projects, build tools, knowledge required</li><li><strong>Workshop Only</strong>: No alternative distribution channel</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Avoid</strong>: Requiring C# for all mods is high barrier</li><li><strong>Learn</strong>: Workshop integration is seamless (consider BepInEx mod browser)</li><li><strong>Contrast</strong>: DINOForge&#39;s YAML + optional C# is more inclusive</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://citiesskylinesmoddingguide.readthedocs.io/en/latest/modding/Getting-Started/" target="_blank" rel="noreferrer">Cities Skylines Modding Guide</a></li><li><a href="https://cslmodding.info/" target="_blank" rel="noreferrer">CSL Modding Info</a></li></ul><hr><h3 id="_11-minecraft-data-packs-fabric-forge" tabindex="-1">11. Minecraft - Data Packs + Fabric/Forge <a class="header-anchor" href="#_11-minecraft-data-packs-fabric-forge" aria-label="Permalink to &quot;11. Minecraft - Data Packs + Fabric/Forge&quot;">​</a></h3><p><strong>Mod Format</strong>: JSON data packs (declarative) or Fabric/Forge mods (Java) <strong>File Structure</strong>: <code>data/{domain}/</code> (JSON), or Java mods with Gradle build</p><p><strong>Load System</strong>:</p><ul><li>Data packs in world folder, auto-discovered</li><li>Fabric/Forge loader handles mod detection and loading</li><li>Modrinth/CurseForge integration</li></ul><p><strong>Content Types</strong>:</p><ul><li>Recipes (crafting, smelting)</li><li>Loot tables (drops, chests)</li><li>Advancements (achievements)</li><li>Custom structures and functions</li><li>Full mechanics via Fabric/Forge mods</li></ul><p><strong>Dependency Management</strong>: Fabric has metadata; many mods don&#39;t declare deps</p><p><strong>Distribution</strong>: Modrinth (best), CurseForge, GitHub</p><p><strong>No-Code Path</strong>: <strong>Full</strong> for data packs (JSON only, no code)</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Data Packs</strong>: Pure JSON content without mods</li><li><strong>Modrinth</strong>: Modern package manager with good UX</li><li><strong>Open Source Ecosystem</strong>: Fabric/Forge are community-driven</li><li><strong>Two Tiers</strong>: Beginners use data packs, advanced use Fabric/Forge</li><li><strong>Large Community</strong>: Millions of players, thousands of mods</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Java modding has high barrier (Gradle, JDK, Maven Central)</li><li>Data packs are JSON-heavy (not intuitive for non-programmers)</li><li>Fabric/Forge dominance means fragmented mod ecosystem (mods choose one, not compatible)</li><li>Dependency management is informal (many mods skip metadata)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: Two-tier system (JSON datapacks for basics, C# for advanced) is ideal</li><li><strong>Adopt</strong>: Modrinth&#39;s UX (mod browser, dependency visualization) is excellent</li><li><strong>Improve</strong>: YAML is clearer than JSON for game configs</li><li><strong>Learn</strong>: Data packs show value of no-code content patches</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://wiki.fabricmc.net/tutorial:custom_resources" target="_blank" rel="noreferrer">Fabric Wiki: Custom Resources</a></li><li><a href="https://docs.minecraftforge.net/en/1.16.x/concepts/data/" target="_blank" rel="noreferrer">Forge Documentation: Data</a></li><li><a href="https://modrinth.com/" target="_blank" rel="noreferrer">Modrinth</a></li></ul><hr><h3 id="_12-skyrim-fallout-4-creation-kit-gui" tabindex="-1">12. Skyrim / Fallout 4 - Creation Kit GUI <a class="header-anchor" href="#_12-skyrim-fallout-4-creation-kit-gui" aria-label="Permalink to &quot;12. Skyrim / Fallout 4 - Creation Kit GUI&quot;">​</a></h3><p><strong>Mod Format</strong>: Binary (ESP/ESM files created by Creation Kit) <strong>File Structure</strong>: <code>.esp</code> (plugin) or <code>.esm</code> (master) files, edited via GUI</p><p><strong>Load System</strong>:</p><ul><li>Creation Kit GUI editor</li><li>Plugins load on top of master files (ESM)</li><li>Light Masters (ESL) reduce plugin slot limits</li></ul><p><strong>Content Types</strong>:</p><ul><li>Quests, NPCs, dialogue</li><li>Items, weapons, armor</li><li>Locations and interiors</li><li>Scripts and behaviors</li></ul><p><strong>Dependency Management</strong>: Master/plugin hierarchy (ESM are masters, ESP are plugins)</p><p><strong>Distribution</strong>: Nexus Mods (largest collection)</p><p><strong>No-Code Path</strong>: Partial—Creation Kit is GUI-based, but editing still requires understanding game data</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Creation Kit GUI</strong>: Official editor, no file format knowledge needed</li><li><strong>Mature Community</strong>: 50K+ mods on Nexus, modding guides for everything</li><li><strong>Plugin System</strong>: Clear dependency chain (ESM → ESP)</li><li><strong>Modding Culture</strong>: Community thrives (Nexus Mods is gold standard)</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li><strong>Binary Format</strong>: Not git-friendly, hard to review changes</li><li><strong>Creation Kit Crashes</strong>: GUI tool is notoriously unstable</li><li><strong>Plugin Limits</strong>: 255 ESP limit (improved by ESL, but still constrained)</li><li><strong>Merge Complexity</strong>: Combining mods requires merging binary files</li><li><strong>No Version Tracking</strong>: Manual plugin management</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Avoid</strong>: Binary format is brittle; DINOForge&#39;s YAML is better</li><li><strong>Learn Negatively</strong>: Creation Kit stability issues show problems with GUI-only tools</li><li><strong>Contrast</strong>: DINOForge&#39;s text-based packs are mergeable and git-friendly</li><li><strong>Target</strong>: Don&#39;t replicate binary plugin system; YAML packs are simpler</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://en.uesp.net/wiki/Skyrim_Mod:Creation_Kit_Usage" target="_blank" rel="noreferrer">UESP Creation Kit Usage</a></li><li><a href="https://falloutck.uesp.net/wiki/Data_File" target="_blank" rel="noreferrer">Fallout4 Creation Kit Wiki</a></li><li><a href="https://www.nexusmods.com/skyrimspecialedition" target="_blank" rel="noreferrer">Nexus Mods Skyrim</a></li></ul><hr><h3 id="_13-openttd-newgrf-nml" tabindex="-1">13. OpenTTD - NewGRF + NML <a class="header-anchor" href="#_13-openttd-newgrf-nml" aria-label="Permalink to &quot;13. OpenTTD - NewGRF + NML&quot;">​</a></h3><p><strong>Mod Format</strong>: NewGRF binary (compiled from NML high-level language) <strong>File Structure</strong>: <code>.grf</code> binary files, source is NML/M4nfo text</p><p><strong>Load System</strong>:</p><ul><li>GRFs loaded from <code>newgrf/</code> folder</li><li>Game applies graphics/content from each GRF in order</li><li>NML compiler generates <code>.grf</code> from <code>.nml</code> source</li><li>Grfcodec tool for lower-level editing</li></ul><p><strong>Content Types</strong>:</p><ul><li>Vehicles and trains</li><li>Buildings and stations</li><li>Cargo types and industries</li><li>Railtypes and roadtypes</li></ul><p><strong>Dependency Management</strong>: Load order specified in game config, no versioning</p><p><strong>Distribution</strong>: Community forums (TT-Forums), <a href="https://steamcommunity.com/workshop/browse/?appid=1536610" target="_blank" rel="noreferrer">Steam Workshop</a></p><p><strong>No-Code Path</strong>: No—requires NML or low-level NFO/M4nfo</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>NML Language</strong>: High-level language compiles to binary GRF (abstraction layer)</li><li><strong>Open Source</strong>: <a href="https://github.com/OpenTTD/grfcodec" target="_blank" rel="noreferrer">Grfcodec</a> and <a href="https://github.com/OpenTTD/nml" target="_blank" rel="noreferrer">NML</a> are open-source (GPL)</li><li><strong>Community Resources</strong>: TT-Forums #openttdcoop has extensive development zone</li><li><strong>Documentation</strong>: Modding is well-documented despite binary format</li><li><strong>Mature Ecosystem</strong>: 20+ year modding tradition</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li><strong>Compilation Step</strong>: Must compile NML → GRF (not live reload)</li><li><strong>Binary Format</strong>: Final <code>.grf</code> is binary (not mergeable)</li><li><strong>Steep Learning Curve</strong>: NML syntax is complex (template language)</li><li><strong>No Dependency Management</strong>: Load order is manual</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: NML shows value of compiling from readable source to binary (but DINOForge should ship YAML, not compile)</li><li><strong>Improve</strong>: DINOForge&#39;s YAML packs should be directly readable (no compilation)</li><li><strong>Learn</strong>: TT-Forums community model shows engaged modding community</li><li><strong>Avoid</strong>: Don&#39;t require compilation; YAML is simpler</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://wiki.openttd.org/en/Manual/NewGRF" target="_blank" rel="noreferrer">OpenTTD NewGRF Manual</a></li><li><a href="https://wiki.openttd.org/en/Development/NewGRF/Development%20Tools" target="_blank" rel="noreferrer">OpenTTD Development Tools</a></li><li><a href="https://github.com/OpenTTD/nml" target="_blank" rel="noreferrer">NML GitHub</a></li></ul><hr><h3 id="_14-victoria-3-jomini-engine-scripting" tabindex="-1">14. Victoria 3 - Jomini Engine Scripting <a class="header-anchor" href="#_14-victoria-3-jomini-engine-scripting" aria-label="Permalink to &quot;14. Victoria 3 - Jomini Engine Scripting&quot;">​</a></h3><p><strong>Mod Format</strong>: PDX script (text-based, Jomini engine) <strong>File Structure</strong>: <code>/common/</code> folders with <code>.txt</code> files</p><p><strong>Load System</strong>:</p><ul><li>Mods in launcher, <code>.mod</code> descriptor files</li><li>Steam Workshop integration</li><li>PDX parser loads <code>.txt</code> files</li><li>Jomini engine (evolved Clausewitz) handles rendering</li></ul><p><strong>Content Types</strong>:</p><ul><li>Game rules, events, decisions</li><li>Character traits and cultures</li><li>Buildings and technologies</li><li>Map modifications</li></ul><p><strong>Dependency Management</strong>: Mod descriptor lists dependencies</p><p><strong>Distribution</strong>: <a href="https://mods.paradoxplaza.com/games/victoria3" target="_blank" rel="noreferrer">Paradox Mods</a>, <a href="https://steamcommunity.com/app/529340/workshop/" target="_blank" rel="noreferrer">Steam Workshop</a></p><p><strong>No-Code Path</strong>: Partial—new rules require PDX script</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Jomini Evolution</strong>: Improved over Clausewitz (64-bit, better performance)</li><li><strong>Documentation</strong>: Victoria 3 modding docs are better than CK3</li><li><strong>Model Modding</strong>: Can replace 3D models (building meshes, etc.)</li><li><strong>Live Editing</strong>: PDX script is relatively readable</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>Same as CK3: proprietary script, incomplete documentation</li><li>Jomini is complex; learning curve is steep</li><li>No code generation tools or validators</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Avoid</strong>: PDX script is proprietary</li><li><strong>Learn</strong>: Jomini shows evolution of game engines (important context, but not directly applicable)</li><li><strong>Contrast</strong>: DINOForge should use open standards (YAML, JSON) instead of proprietary formats</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://vic3.paradoxwikis.com/Modding" target="_blank" rel="noreferrer">Victoria 3 Modding Wiki</a></li><li><a href="https://www.paradoxinteractive.com/games/victoria-3/news/victoria-3-dev-diary-60-modding" target="_blank" rel="noreferrer">Dev Diary #60: Modding</a></li></ul><hr><h3 id="_15-dwarf-fortress-raw-text-modding" tabindex="-1">15. Dwarf Fortress - RAW Text Modding <a class="header-anchor" href="#_15-dwarf-fortress-raw-text-modding" aria-label="Permalink to &quot;15. Dwarf Fortress - RAW Text Modding&quot;">​</a></h3><p><strong>Mod Format</strong>: RAW text files (declarative object definitions) <strong>File Structure</strong>: Text files in <code>/mods/</code> or <code>/data/vanilla/*/objects/</code></p><p><strong>Load System</strong>:</p><ul><li>Mods folder auto-discovered</li><li>RAW files define creatures, items, materials, etc.</li><li>SELECT/CUT tokens allow partial overrides (don&#39;t need full file)</li><li>Game merges mods at startup</li></ul><p><strong>Content Types</strong>:</p><ul><li>Creatures (bodies, castes, interactions)</li><li>Materials and properties</li><li>Items and buildings</li><li>Civilizations and entities</li><li>Languages and translations</li></ul><p><strong>Dependency Management</strong>: None (all mods are independent)</p><p><strong>Distribution</strong>: <a href="https://steamcommunity.com/app/975370/community/" target="_blank" rel="noreferrer">Steam Workshop</a>, <a href="https://dffd.bay12games.com/" target="_blank" rel="noreferrer">DFFD (Dwarf Fortress File Depot)</a></p><p><strong>No-Code Path</strong>: <strong>Full</strong> — all modding is RAW text, no code required</p><p><strong>Key Strengths</strong>:</p><ol><li><strong>Pure RAW Modding</strong>: Text files, no compilation, no code</li><li><strong>SELECT/CUT Tokens</strong>: Mods only need to specify what they change (don&#39;t need full file copy)</li><li><strong>Declarative Format</strong>: Intuitive structure (BODY_DETAIL_TEMPLATE blocks)</li><li><strong>Community Culture</strong>: Strong modding tradition, 20+ year history</li><li><strong>OpenSource Engine</strong>: Community maintains compatibility tools (PyDwarf, DF Tools, Material Helper)</li><li><strong>Zero Barrier to Entry</strong>: No coding, no special tools needed</li></ol><p><strong>Key Weaknesses</strong>:</p><ol><li>No dependency management or versioning</li><li>Mods can conflict silently (last definition wins)</li><li>RAW syntax is verbose (long files)</li><li>Limited to DF&#39;s design scope (can&#39;t add new creature properties without engine mods)</li></ol><p><strong>Relevance to DINOForge</strong>:</p><ul><li><strong>Adopt</strong>: RAW&#39;s SELECT token is brilliant—DINOForge should allow partial overrides</li><li><strong>Adopt</strong>: Pure declarative format with no code barrier is ideal</li><li><strong>Target</strong>: <code>faction.yaml</code> + <code>units.yaml</code> for modders to only override what they need</li><li><strong>Learn</strong>: Dwarf Fortress modding shows that large games can thrive with text-based modding</li><li><strong>Plan</strong>: Community tools (like Material Helper) show value of validator/helper tools</li></ul><p><strong>Sources</strong>:</p><ul><li><a href="https://dwarffortresswiki.org/Modding" target="_blank" rel="noreferrer">Dwarf Fortress Modding Wiki</a></li><li><a href="https://steamcommunity.com/sharedfiles/filedetails/?id=2903013900" target="_blank" rel="noreferrer">Steam Guide: Modding &amp; Custom Workshops</a></li><li><a href="https://github.com/pineapplemachine/PyDwarf/blob/master/docs/modding.md" target="_blank" rel="noreferrer">PyDwarf Documentation</a></li></ul><hr><h2 id="key-insights-for-dinoforge" tabindex="-1">Key Insights for DINOForge <a class="header-anchor" href="#key-insights-for-dinoforge" aria-label="Permalink to &quot;Key Insights for DINOForge&quot;">​</a></h2><h3 id="_1-no-code-path-is-essential" tabindex="-1">1. <strong>No-Code Path is Essential</strong> <a class="header-anchor" href="#_1-no-code-path-is-essential" aria-label="Permalink to &quot;1. **No-Code Path is Essential**&quot;">​</a></h3><p>Games with the strongest modding communities (Stardew Valley, RimWorld, Dwarf Fortress, Minecraft datapacks) all support no-code content creation:</p><ul><li><strong>Stardew Valley</strong>: JSON Content Patcher (zero code)</li><li><strong>RimWorld</strong>: XML defs (zero code, optional C# patches)</li><li><strong>Dwarf Fortress</strong>: RAW text (zero code, pure declarative)</li><li><strong>Minecraft</strong>: JSON datapacks (zero code)</li></ul><p><strong>DINOForge Action</strong>:</p><ul><li>Core pack format (YAML) must be 100% code-free</li><li>Must allow modders to create complete units, factions, buildings, doctrines without C#</li><li>Optional C# for complex behaviors, but not required for balance/content</li></ul><h3 id="_2-text-based-formats-trump-binary" tabindex="-1">2. <strong>Text-Based Formats Trump Binary</strong> <a class="header-anchor" href="#_2-text-based-formats-trump-binary" aria-label="Permalink to &quot;2. **Text-Based Formats Trump Binary**&quot;">​</a></h3><p>Games stuck with binary formats (Total War Warhammer III <code>.pack</code>, Sims 4 <code>.package</code>, Skyrim <code>.esp</code>) suffer from:</p><ul><li>Non-mergeable conflicts (can&#39;t diff or review changes)</li><li>Tool dependency (RPFM, Sims4Studio, Creation Kit)</li><li>Git-unfriendly (can&#39;t version control easily)</li><li>High friction for collaboration</li></ul><p>Games with text formats (Dwarf Fortress RAW, Factorio Lua, RimWorld XML, Paradox PDX script) show:</p><ul><li>Community contributions are easier (edit <code>.txt</code> files, not binary)</li><li>Version control is natural (git diff shows exact changes)</li><li>Merge conflicts can be resolved manually</li></ul><p><strong>DINOForge Action</strong>:</p><ul><li>Stay with YAML/JSON (human-readable, git-friendly)</li><li>Never ship binary pack format; always ship source</li><li>Design packs to be mergeable (don&#39;t require complex tool workflow)</li></ul><h3 id="_3-partial-overrides-beat-full-replacement" tabindex="-1">3. <strong>Partial Overrides Beat Full Replacement</strong> <a class="header-anchor" href="#_3-partial-overrides-beat-full-replacement" aria-label="Permalink to &quot;3. **Partial Overrides Beat Full Replacement**&quot;">​</a></h3><p>Dwarf Fortress RAW&#39;s SELECT token is brilliant:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[SELECT:creature:dwarf]</span></span>
<span class="line"><span>[BODY:DWARF_BODY]  # only override body, inherit everything else</span></span></code></pre></div><p>This beats &quot;replace entire file&quot; approaches because:</p><ul><li>Mods don&#39;t need to copy 90% of vanilla content</li><li>Maintenance is easier (changes to vanilla don&#39;t break mods)</li><li>Conflicts are fewer (mod only touches what it cares about)</li></ul><p>RimWorld defs also support this via inheritance (child defs inherit from parent).</p><p><strong>DINOForge Action</strong>:</p><ul><li>Design pack YAML to allow partial overrides</li><li>Example: <code>units.yaml</code> can define a unit with <code>base: vanilla.archer</code> and just override <code>attack: 8</code></li><li>Don&#39;t require full unit definitions in every pack</li><li>Use JSON Merge Patch (RFC 7386) or similar for merging</li></ul><h3 id="_4-dependency-management-matters" tabindex="-1">4. <strong>Dependency Management Matters</strong> <a class="header-anchor" href="#_4-dependency-management-matters" aria-label="Permalink to &quot;4. **Dependency Management Matters**&quot;">​</a></h3><p>CKAN&#39;s semantic versioning is the gold standard:</p><ul><li><code>depends_on: [&quot;ecs-bridge&gt;=1.0.0, &lt;2.0.0&quot;]</code></li><li>Automatic conflict detection</li><li>Version lockfiles for reproducibility</li></ul><p>RimWorld&#39;s load order is manual (brittle). Bannerlord has no versioning (fragile).</p><p><strong>DINOForge Action</strong>:</p><ul><li>Require <code>pack.yaml</code> to include semantic versions</li><li>Implement CKAN-style resolver (or wrap NuGet)</li><li>Validate: a pack can&#39;t depend on conflicting versions</li><li>Store lockfiles in git (reproducible builds)</li></ul><h3 id="_5-multi-stage-loading-prevents-conflicts" tabindex="-1">5. <strong>Multi-Stage Loading Prevents Conflicts</strong> <a class="header-anchor" href="#_5-multi-stage-loading-prevents-conflicts" aria-label="Permalink to &quot;5. **Multi-Stage Loading Prevents Conflicts**&quot;">​</a></h3><p>Factorio&#39;s data lifecycle (data → updates → final-fixes) is genius:</p><ol><li>Data stage: Define all new prototypes</li><li>Updates stage: Modify existing prototypes</li><li>Final-fixes stage: Last-minute balance tweaks</li></ol><p>This prevents load-order spaghetti (Bannerlord, Total War suffer here).</p><p><strong>DINOForge Action</strong>:</p><ul><li>Design pack loading in stages: <ol><li>Base content (units, buildings, factions)</li><li>Balance overrides (stat adjustments)</li><li>Conflict resolution (cross-pack rules)</li></ol></li><li>Document which stage each yaml file is loaded in</li><li>Validators should check for stage violations</li></ul><h3 id="_6-avoid-the-rts-modding-pitfalls" tabindex="-1">6. <strong>Avoid the RTS Modding Pitfalls</strong> <a class="header-anchor" href="#_6-avoid-the-rts-modding-pitfalls" aria-label="Permalink to &quot;6. **Avoid the RTS Modding Pitfalls**&quot;">​</a></h3><p><strong>Pitfall 1: Call to Arms / Men of War: Assault Squad 2</strong></p><ul><li>Binary mission files (not mergeable)</li><li>Proprietary script language (undocumented)</li><li>No dependency management</li><li>High tool requirement (only one editor works)</li></ul><p><strong>Pitfall 2: StarCraft 2 Arcade</strong></p><ul><li>Requires in-game editor (fragile, hard to use)</li><li>No git integration</li><li>Distribution is only via Blizzard (not open)</li></ul><p><strong>Pitfall 3: Company of Heroes</strong></p><ul><li>XML modding but no clear content scope</li><li>Mods often conflict with each other</li><li>Load order is fragile</li></ul><p><strong>DINOForge Avoidance</strong>:</p><ul><li>Stay with text-based YAML (mergeable, git-friendly)</li><li>Document exactly what can be modded (schema is law)</li><li>Provide clear load stages (no spaghetti)</li><li>Support distribution beyond BepInEx (Nexus, GitHub Releases, etc.)</li></ul><h3 id="_7-community-distribution-matters" tabindex="-1">7. <strong>Community Distribution Matters</strong> <a class="header-anchor" href="#_7-community-distribution-matters" aria-label="Permalink to &quot;7. **Community Distribution Matters**&quot;">​</a></h3><p>Games with thriving mod communities use <strong>multiple distribution channels</strong>:</p><ul><li>Stardew Valley: Nexus Mods + CurseForge (not just official portal)</li><li>RimWorld: Steam Workshop + Nexus (community chooses)</li><li>Minecraft: Modrinth + CurseForge (multiple loaders, not vendor lock-in)</li></ul><p>Games with single distribution (Cities Skylines Steam Workshop only) have less vibrant communities.</p><p><strong>DINOForge Action</strong>:</p><ul><li>Support Nexus Mods as primary (best UX for modders)</li><li>Add GitHub Releases support (direct download)</li><li>Don&#39;t force BepInEx mod database-only</li><li>Consider building simple mod browser (like SMAPI/Nexus do)</li></ul><h3 id="_8-validation-tooling-reduce-errors" tabindex="-1">8. <strong>Validation &amp; Tooling Reduce Errors</strong> <a class="header-anchor" href="#_8-validation-tooling-reduce-errors" aria-label="Permalink to &quot;8. **Validation &amp; Tooling Reduce Errors**&quot;">​</a></h3><p>SMAPI&#39;s <a href="https://smapi.io/json" target="_blank" rel="noreferrer">smapi.io/json</a> validator is a game-changer:</p><ul><li>Validates manifest.json and content.json before load</li><li>Catches typos, missing dependencies, version conflicts</li><li>Prevents &quot;mod won&#39;t load&quot; silent failures</li></ul><p>DINOForge should ship validators:</p><ul><li><code>dinoforge validate pack.yaml</code> (checks schema, dependencies, references)</li><li>Web validator (like SMAPI) for GitHub PR checks</li><li>IDE support (VS Code extension with JSON Schema)</li></ul><h3 id="_9-optional-beginner-ui-tools-boost-adoption" tabindex="-1">9. <strong>Optional Beginner UI Tools Boost Adoption</strong> <a class="header-anchor" href="#_9-optional-beginner-ui-tools-boost-adoption" aria-label="Permalink to &quot;9. **Optional Beginner UI Tools Boost Adoption**&quot;">​</a></h3><p>Games with GUI tools see more modders:</p><ul><li>Mount &amp; Blade II: Official scene editor + SubModule wizard</li><li>Skyrim: Creation Kit (despite being buggy, it lowers barrier)</li><li>Sims 4: Sims4Studio (visual editor, non-programmers can mod)</li></ul><p>DINOForge doesn&#39;t need this immediately, but consider:</p><ul><li>VS Code JSON Schema for YAML editing (already works)</li><li>Web-based pack builder (future)</li><li>In-game mod browser (future)</li></ul><h3 id="_10-licensing-open-source-matters" tabindex="-1">10. <strong>Licensing &amp; Open Source Matters</strong> <a class="header-anchor" href="#_10-licensing-open-source-matters" aria-label="Permalink to &quot;10. **Licensing &amp; Open Source Matters**&quot;">​</a></h3><p>OpenTTD, Minecraft (community tools), Dwarf Fortress all benefit from:</p><ul><li>Open-source modding tools (Grfcodec, Fabric, PyDwarf)</li><li>Community wiki documentation (not proprietary)</li><li>GPL/MIT licenses (mods are shared freely)</li></ul><p>Paradox&#39;s proprietary PDX script limits documentation (leading to sparse guides).</p><p><strong>DINOForge Action</strong>:</p><ul><li>Ship all tools as open-source (PackCompiler, DumpTools, CLI)</li><li>Document YAML schema on wiki (not closed)</li><li>Encourage community tool development (e.g., pack validators, web browser)</li><li>MIT/GPL license ensures tools stay free</li></ul><hr><h2 id="recommendations-for-dinoforge-implementation" tabindex="-1">Recommendations for DINOForge Implementation <a class="header-anchor" href="#recommendations-for-dinoforge-implementation" aria-label="Permalink to &quot;Recommendations for DINOForge Implementation&quot;">​</a></h2><h3 id="short-term-current" tabindex="-1">Short Term (Current) <a class="header-anchor" href="#short-term-current" aria-label="Permalink to &quot;Short Term (Current)&quot;">​</a></h3><ol><li><strong>Keep YAML pack format</strong> as-is (excellent design)</li><li><strong>Add partial override support</strong> (allow <code>base: unit_archetype</code> in units.yaml)</li><li><strong>Implement CKAN-style dependency resolver</strong> with semantic versioning</li><li><strong>Add validation tool</strong> (<code>dinoforge validate packs/</code>)</li><li><strong>Schema as contract</strong> (JSON Schema for pack.yaml, units.yaml, doctrines.yaml)</li></ol><h3 id="medium-term-m6" tabindex="-1">Medium Term (M6) <a class="header-anchor" href="#medium-term-m6" aria-label="Permalink to &quot;Medium Term (M6)&quot;">​</a></h3><ol><li><strong>Multi-stage loading</strong> (data → balance → conflict-resolution)</li><li><strong>Nexus Mods integration</strong> (upload/download support)</li><li><strong>VS Code extension</strong> with JSON Schema validation</li><li><strong>Web validator</strong> (smapi.io-style)</li><li><strong>GitHub Actions template</strong> for pack authors</li></ol><h3 id="long-term-m7" tabindex="-1">Long Term (M7+) <a class="header-anchor" href="#long-term-m7" aria-label="Permalink to &quot;Long Term (M7+)&quot;">​</a></h3><ol><li><strong>Web-based pack builder</strong> (no YAML needed for simple packs)</li><li><strong>In-game mod browser</strong> (in BepInEx UI)</li><li><strong>Community tools</strong> (diff viewer, conflict detector, balance calculator)</li><li><strong>Scripting guide</strong> (when/why to use C# plugins)</li></ol><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>DINOForge&#39;s YAML-based, text-driven pack system is <strong>already superior</strong> to most industry approaches. The key is to:</p><ol><li><strong>Emphasize the no-code path</strong> (make YAML the primary way to mod)</li><li><strong>Support partial overrides</strong> (don&#39;t force full file replacement)</li><li><strong>Add robust dependency management</strong> (CKAN-style versioning)</li><li><strong>Validate early and often</strong> (catch errors before game load)</li><li><strong>Avoid the RTS pitfalls</strong> (binary formats, undocumented scripting, single distribution)</li><li><strong>Community distribution</strong> (Nexus, GitHub, not just BepInEx)</li></ol><p>If DINOForge executes on these principles, it will rival or exceed Factorio, Stardew Valley, and RimWorld in modding accessibility and community adoption.</p><hr><h2 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">​</a></h2><h3 id="primary-research" tabindex="-1">Primary Research <a class="header-anchor" href="#primary-research" aria-label="Permalink to &quot;Primary Research&quot;">​</a></h3><ul><li><a href="https://wiki.factorio.com/Modding" target="_blank" rel="noreferrer">Factorio Modding Wiki</a></li><li><a href="https://lua-api.factorio.com/latest/" target="_blank" rel="noreferrer">Factorio Lua API</a></li><li><a href="https://stardewvalleywiki.com/Modding:Content_Patcher" target="_blank" rel="noreferrer">Content Patcher Documentation</a></li><li><a href="https://smapi.io/" target="_blank" rel="noreferrer">SMAPI</a></li><li><a href="https://rimworldmodding.wiki.gg/" target="_blank" rel="noreferrer">RimWorld Modding Wiki</a></li><li><a href="https://ck3.paradoxwikis.com/Modding" target="_blank" rel="noreferrer">CK3 Modding Wiki</a></li><li><a href="https://steamcommunity.com/workshop/browse/?appid=281990" target="_blank" rel="noreferrer">Stellaris Workshop</a></li><li><a href="https://github.com/Frodo45127/rpfm" target="_blank" rel="noreferrer">RPFM GitHub</a></li><li><a href="https://github.com/KSP-CKAN/CKAN" target="_blank" rel="noreferrer">CKAN GitHub</a></li><li><a href="https://docs.bannerlordmodding.com/" target="_blank" rel="noreferrer">Bannerlord Modding Docs</a></li><li><a href="https://sims-4-modding.fandom.com/" target="_blank" rel="noreferrer">Sims 4 Modding Wiki</a></li><li><a href="https://citiesskylinesmoddingguide.readthedocs.io/" target="_blank" rel="noreferrer">Cities Skylines Modding</a></li><li><a href="https://wiki.fabricmc.net/tutorial:custom_resources" target="_blank" rel="noreferrer">Minecraft Data Packs</a></li><li><a href="https://en.uesp.net/wiki/Skyrim_Mod:Creation_Kit_Usage" target="_blank" rel="noreferrer">Skyrim Creation Kit</a></li><li><a href="https://wiki.openttd.org/en/Manual/NewGRF" target="_blank" rel="noreferrer">OpenTTD NewGRF</a></li><li><a href="https://vic3.paradoxwikis.com/Modding" target="_blank" rel="noreferrer">Victoria 3 Modding</a></li><li><a href="https://dwarffortresswiki.org/Modding" target="_blank" rel="noreferrer">Dwarf Fortress Modding</a></li></ul><h3 id="comparative-references" tabindex="-1">Comparative References <a class="header-anchor" href="#comparative-references" aria-label="Permalink to &quot;Comparative References&quot;">​</a></h3><ul><li><a href="https://lua-api.factorio.com/latest/auxiliary/data-lifecycle.html" target="_blank" rel="noreferrer">Factorio Lua Data Lifecycle</a></li><li><a href="https://docs.bannerlordmodding.com/_xmldocs/submodule.html" target="_blank" rel="noreferrer">Mount &amp; Blade SubModule.xml</a></li><li><a href="https://github.com/KSP-CKAN/CKAN/wiki" target="_blank" rel="noreferrer">CKAN Metadata Spec</a></li><li><a href="https://docs.minecraftforge.net/en/1.16.x/concepts/data/" target="_blank" rel="noreferrer">Minecraft Datapacks (Forge)</a></li><li><a href="https://github.com/OpenTTD/nml" target="_blank" rel="noreferrer">NML GitHub</a></li><li><a href="https://github.com/pineapplemachine/PyDwarf" target="_blank" rel="noreferrer">PyDwarf Documentation</a></li></ul>`,360)])])}const u=t(a,[["render",n]]);export{m as __pageData,u as default};
